        radial-gradient(circle at 50% 15%, #17245a 0%, transparent 35%),
        radial-gradient(circle at 15% 80%, #2c0d4e 0%, transparent 32%),
        var(--bg);
      color: #eafcff;
      font-family: Arial, Helvetica, sans-serif;
    }

    body {
      display: grid;
      place-items: center;
    }

    #game-shell {
      position: relative;
      width: min(96vw, 1000px);
      aspect-ratio: 16 / 10;
      max-height: 94vh;
      border: 1px solid rgba(39, 245, 255, 0.5);
      border-radius: 16px;
      overflow: hidden;
      background: #050613;
      box-shadow:
        0 0 12px rgba(39, 245, 255, 0.55),
        0 0 45px rgba(154, 92, 255, 0.26),
        inset 0 0 30px rgba(39, 245, 255, 0.07);
      touch-action: none;
    }

    canvas {
      display: block;
      width: 100%;
      height: 100%;
      cursor: crosshair;
    }

    #hud {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: clamp(10px, 2vw, 18px) clamp(14px, 3vw, 28px);
      pointer-events: none;
      text-transform: uppercase;
      letter-spacing: 0.12em;
      font-size: clamp(10px, 1.4vw, 15px);
      font-weight: bold;
      text-shadow: 0 0 8px currentColor;
    }

    .hud-group {
      display: flex;
      gap: clamp(12px, 3vw, 34px);
    }

    .hud-item {
      color: #d9faff;
      white-space: nowrap;
    }

    .hud-item span {
      color: var(--cyan);
      margin-left: 6px;
    }

    #overlay {
      position: absolute;
      inset: 0;
      display: grid;
      place-items: center;
      padding: 24px;
      background: linear-gradient(rgba(2, 3, 13, 0.45), rgba(2, 3, 13, 0.8));
      transition: opacity 0.25s ease;
    }

    #overlay.hidden {
      opacity: 0;
      pointer-events: none;
    }

    .panel {
      width: min(90%, 520px);
      text-align: center;
      padding: clamp(24px, 5vw, 48px);
      border: 1px solid rgba(39, 245, 255, 0.5);
      border-radius: 18px;
      background: var(--panel);
      box-shadow:
        0 0 20px rgba(39, 245, 255, 0.23),
        0 0 60px rgba(255, 42, 166, 0.12),
        inset 0 0 30px rgba(39, 245, 255, 0.04);
      backdrop-filter: blur(8px);
    }

    h1 {
      margin: 0 0 12px;
      color: var(--cyan);
      font-size: clamp(30px, 6vw, 64px);
      letter-spacing: 0.08em;
      text-transform: uppercase;
      text-shadow:
        0 0 8px var(--cyan),
        0 0 24px rgba(39, 245, 255, 0.7);
    }

    .subtitle {
      margin: 0 0 25px;
      color: #c8cce9;
      line-height: 1.6;
      font-size: clamp(12px, 1.7vw, 16px);
    }

    .key {
      display: inline-block;
