      padding: 2px 7px;
      margin: 0 2px;
      border: 1px solid rgba(39, 245, 255, 0.55);
      border-radius: 4px;
      color: var(--cyan);
      font-size: 0.85em;
      box-shadow: inset 0 0 7px rgba(39, 245, 255, 0.12);
    }

    button {
      border: 1px solid var(--cyan);
      border-radius: 8px;
      padding: 13px 25px;
      background: rgba(39, 245, 255, 0.1);
      color: #ecffff;
      cursor: pointer;
      font: inherit;
      font-size: clamp(13px, 1.8vw, 16px);
      font-weight: bold;
      letter-spacing: 0.13em;
      text-transform: uppercase;
      box-shadow: 0 0 15px rgba(39, 245, 255, 0.35);
      transition: 0.18s ease;
    }

    button:hover,
    button:focus-visible {
      background: rgba(39, 245, 255, 0.26);
      box-shadow: 0 0 25px rgba(39, 245, 255, 0.75);
      transform: translateY(-2px);
      outline: none;
